    'ظ':{ ch:'ظ', name:'ظاء' }, 'ع':{ ch:'ع', name:'عين' }, 'غ':{ ch:'غ', name:'غين' },
    'ف':{ ch:'ف', name:'فاء' }, 'ق':{ ch:'ق', name:'قاف' }, 'ك':{ ch:'ك', name:'كاف' },
    'ل':{ ch:'ل', name:'لام' }, 'م':{ ch:'م', name:'ميم' }, 'ن':{ ch:'ن', name:'نون' },
    'ه':{ ch:'ه', name:'هاء' }, 'و':{ ch:'و', name:'واو' }, 'ي':{ ch:'ي', name:'ياء' }, 'ى':{ ch:'ى', name:'ألف مقصورة' },
    'ة':{ ch:'ة', name:'تاء مربوطة' }
