    'ج':{ ch:'Γ', name:'غاما' }, 'ح':{ ch:'Η', name:'إيتا' }, 'خ':{ ch:'Χ', name:'خي' },
    'د':{ ch:'Δ', name:'دلتا' }, 'ذ':{ ch:'Δ', name:'دلتا' }, 'ر':{ ch:'Ρ', name:'رو' },
    'ز':{ ch:'Ζ', name:'زيتا' }, 'س':{ ch:'Σ', name:'سيغما' }, 'ش':{ ch:'Ξ', name:'كسي' },
    'ص':{ ch:'Σ', name:'سيغما' }, 'ض':{ ch:'Δ', name:'دلتا' }, 'ط':{ ch:'Τ', name:'تاو' },
