    'ه':{ ch:'Η', name:'إيتا' }, 'و':{ ch:'Υ', name:'أبسيلون' }, 'ي':{ ch:'Ι', name:'يوتا' }, 'ى':{ ch:'Ι', name:'يوتا' },
