  // خريطة صوتية تقريبية تحوّل الحروف اللاتينية (الإنجليزية والفرنسية والإسبانية والألمانية...
  // وأي لغة أخرى تُكتب بالحروف اللاتينية) إلى أقرب حرف عربي، حتى يمكن استخدام أي حرف من
  // هذه اللغات كمدخل بديل عن الحرف العربي عند كتابة الاسم في كاتب الاسم التفاعلي.
  const LATIN_TO_ARABIC = {
    a:'ا', b:'ب', c:'ك', d:'د', e:'ي', f:'ف', g:'ج', h:'ه', i:'ي', j:'ج',
    k:'ك', l:'ل', m:'م', n:'ن', o:'و', p:'ب', q:'ق', r:'ر', s:'س', t:'ت',
    u:'و', v:'ف', w:'و', x:'ك', y:'ي', z:'ز'
  };
  // يبحث عن الرمز المناسب لأي حرف مهما كانت لغته: يجرّب الحرف كما هو (عربي غالبًا)،
  // ثم يبسّط الحروف اللاتينية المنقوطة (é, ñ, ü...) ويحاول عبر الخريطة الصوتية أعلاه.
  function findSymbolForChar(ch, map){
    if (map[ch]) return map[ch];
    const simplified = ch.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
    if (map[simplified]) return map[simplified];
    const arabicEquivalent = LATIN_TO_ARABIC[simplified];
    if (arabicEquivalent && map[arabicEquivalent]) return map[arabicEquivalent];
    return null;
  }

  const langModal = document.getElementById('language-modal');
  const langTag = document.getElementById('lang-modal-tag');
  const langTitle = document.getElementById('lang-modal-title');
  const langDesc = document.getElementById('lang-modal-desc');
  const langAlphabetGrid = document.getElementById('lang-alphabet');
  const langNameInput = document.getElementById('lang-name-input');
  const langCartouche = document.getElementById('lang-cartouche');

  function openLanguageModal(wingKey){
    const data = LANG_DATA[wingKey];
    if (!data || !langModal) return;

    langTag.textContent = 'تعلم لغة الحضارة';
    langTitle.textContent = data.title;
    langDesc.textContent = data.desc;

    const seen = new Set();
    langAlphabetGrid.innerHTML = Object.entries(data.map)
      .filter(([, sym]) => (seen.has(sym.ch) ? false : (seen.add(sym.ch), true))) // إزالة التكرار البصري
      .map(([letter, sym]) => `
        <div class="hiero-letter" title="${sym.name}">
          <span class="real-glyph">${sym.ch}</span>
          <span class="ar">${letter}</span>
        </div>`).join('');

    langNameInput.value = '';
    function renderLangCartouche(){
      const value = (langNameInput.value || '').trim();
      if (!value) {
        langCartouche.classList.add('empty');
        langCartouche.innerHTML = 'اكتب اسمك أعلاه لتراه بحروف هذه الحضارة';
        return;
      }
      langCartouche.classList.remove('empty');
      const glyphs = [...value].reverse().map(ch => {
        const sym = findSymbolForChar(ch, data.map);
        if (!sym) return '';
        return `<span class="glyph-slot real-glyph-slot">${sym.ch}</span>`;
      }).join('');
      langCartouche.innerHTML = glyphs || 'لم نتعرّف على هذه الحروف، جرّب حروفًا عربية أو حروفًا لاتينية (إنجليزية، فرنسية...)';
    }
    langNameInput.oninput = renderLangCartouche;
    renderLangCartouche();

    openModal(langModal);
  }

  document.getElementById('wing-language-btn')?.addEventListener('click', () => {
    if (!currentWingKey) return;
    closeModal(wingModal);
    openLanguageModal(currentWingKey);
  });
  document.getElementById('gallery-language-btn')?.addEventListener('click', () => {
    if (!currentWingKey) return;
    openLanguageModal(currentWingKey);
  });

